1	// SessionManager runs Claude Code as a child process and turns its
2	// stream-json output into a stream of structured events that the UI can
3	// consume. It also drives the policy engine, change tracker, and audit log.
4	import { spawn } from 'node:child_process';
5	import { randomUUID } from 'node:crypto';
6	import path from 'node:path';
7	import fs from 'node:fs';
8	import { EventEmitter } from 'node:events';
9	
10	import { ChangeTracker, captureContents } from './changeTracker.js';
11	import { evaluateToolUse, getPolicy } from './policyEngine.js';
12	
13	let _id = 0;
14	const nextId = () => `s${Date.now().toString(36)}${(_id++).toString(36)}`;
15	
16	const MAX_EVENTS = 5000;
17	
18	export class SessionManager extends EventEmitter {
19	  constructor({ store } = {}) {
20	    super();
21	    this.sessions = new Map();
22	    this.store = store || null;
23	  }
24	
25	  list() {
26	    return Array.from(this.sessions.values()).map((s) => s.summary());
27	  }
28	
29	  get(id) {
30	    return this.sessions.get(id);
31	  }
32	
33	  create({ workdir, name, policyId }) {
34	    let abs = path.resolve(workdir || process.cwd());
35	    if (!fs.existsSync(abs) || !fs.statSync(abs).isDirectory()) {
36	      throw new Error(`工作目录不存在: ${abs}`);
37	    }
38	    // Resolve symlinks (e.g. /tmp -> /private/tmp on macOS) so paths the
39	    // CLI reports later match the workdir we record.
40	    try {
41	      abs = fs.realpathSync(abs);
42	    } catch {}
43	    const session = new Session({
44	      id: nextId(),
45	      workdir: abs,
46	      name: name || path.basename(abs),
47	      policyId: policyId || 'balanced',
48	      bus: this,
49	    });
50	    session._store = this.store;
51	    this.sessions.set(session.id, session);
52	    this.emit('session:created', session.summary());
53	    this.store?.scheduleSave(session);
54	    return session;
55	  }
56	
57	  remove(id) {
58	    const s = this.sessions.get(id);
59	    if (!s) return false;
60	    s.stop();
61	    this.sessions.delete(id);
62	    this.store?.remove(id);
63	    this.emit('session:removed', { id });
64	    return true;
65	  }
66	
67	  // Rebuild a Session from a persisted payload after a server restart.
68	  // Live-only fields (activeChild/activeTurn/pendingApprovals) are reset,
69	  // and a synthetic `session:interrupted` event is appended so the audit
70	  // log reflects the gap.
71	  hydrate(persisted) {
72	    const session = new Session({
73	      id: persisted.id,
74	      workdir: persisted.workdir,
75	      name: persisted.name,
76	      policyId: persisted.policyId,
77	      bus: this,
78	    });
79	    session._store = this.store;
80	
81	    // Restore audit/state fields verbatim.
82	    session.createdAt = persisted.createdAt;
83	    session.endedAt = persisted.endedAt;
84	    session.claudeSessionId = persisted.claudeSessionId || null;
85	    session.turns = Array.isArray(persisted.turns) ? persisted.turns : [];
86	    session.events = Array.isArray(persisted.events) ? persisted.events : [];
87	    session.tools = Array.isArray(persisted.tools) ? persisted.tools : [];
88	    session.changes = Array.isArray(persisted.changes) ? persisted.changes : [];
89	    session.lastChangeMap = persisted.lastChangeMap || {};
90	    session.fileBaselines = persisted.fileBaselines || {};
91	
92	    // Live fields are always fresh.
93	    session.activeChild = null;
94	    session.activeTurn = null;
95	    session.pendingApprovals = new Map();
96	
97	    const workdirOk =
98	      fs.existsSync(persisted.workdir) && fs.statSync(persisted.workdir).isDirectory();
99	    if (workdirOk) {
100	      // Re-snapshot so the next turn diffs against the post-restart state.
101	      session.changeTracker.takeSnapshot();
102	      let status = persisted.status;
103	      if (status === 'running' || status === 'waiting' || status === 'cancelling') status = 'idle';
104	      session.status = status || 'idle';
105	    } else {
106	      session.status = 'error';
107	    }
108	
109	    // Mark any approvals that were pending at shutdown as abandoned.
110	    if (Array.isArray(persisted.pendingApprovals)) {
111	      for (const a of persisted.pendingApprovals) {
112	        session._record({
113	          type: 'approval:abandoned',
114	          toolUseId: a.toolUseId || a.id,
115	          tool: a.tool,
116	        });
117	      }
118	    }
119	
120	    if (!workdirOk) {
121	      session._record({ type: 'session:workdir-missing', workdir: persisted.workdir });
122	    }
123	    session._record({ type: 'session:interrupted' });
124	
125	    this.sessions.set(session.id, session);
126	    this.emit('session:created', session.summary());
127	    return session;
128	  }
129	}
