1	// Tracks code changes within a workdir by snapshotting file mtimes/hashes
2	// and computing diffs after each Claude turn. Falls back gracefully when the
3	// workdir is not a git repository.
4	import { execFileSync } from 'node:child_process';
5	import fs from 'node:fs';
6	import path from 'node:path';
7	import crypto from 'node:crypto';
8	
9	export class ChangeTracker {
10	  constructor(workdir) {
11	    this.workdir = workdir;
12	    this.isGit = isGitRepo(workdir);
13	    this.snapshot = null;
14	  }
15	
16	  // Take a snapshot of current files (relative path -> hash). Uses git when
17	  // available (cheap), otherwise walks the filesystem.
18	  takeSnapshot() {
19	    this.snapshot = scanWorkdir(this.workdir);
20	    return this.snapshot;
21	  }
22	
23	  // Diff vs the previous snapshot, return list of file changes plus summary.
24	  diff() {
25	    const prev = this.snapshot || {};
26	    const curr = scanWorkdir(this.workdir);
27	    const changes = [];
28	    const allKeys = new Set([...Object.keys(prev), ...Object.keys(curr)]);
29	    for (const rel of allKeys) {
30	      const before = prev[rel];
31	      const after = curr[rel];
32	      if (!before && after) {
33	        changes.push({ relPath: rel, kind: 'added', size: after.size });
34	      } else if (before && !after) {
35	        changes.push({ relPath: rel, kind: 'deleted', size: before.size });
36	      } else if (before && after && before.hash !== after.hash) {
37	        changes.push({ relPath: rel, kind: 'modified', size: after.size });
38	      }
39	    }
40	    // Update snapshot to current for next diff
41	    this.snapshot = curr;
42	    return changes;
43	  }
44	
45	  // Read raw file content for diff display.
46	  readFile(relPath, maxBytes = 200_000) {
47	    const full = path.join(this.workdir, relPath);
48	    try {
49	      const stat = fs.statSync(full);
50	      if (stat.size > maxBytes) {
51	        return { content: null, size: stat.size, tooLarge: true };
52	      }
53	      const buf = fs.readFileSync(full);
54	      if (isBinary(buf)) return { content: null, size: stat.size, binary: true };
55	      return { content: buf.toString('utf8'), size: stat.size };
56	    } catch (e) {
57	      return { content: null, error: e.message };
58	    }
59	  }
60	
61	  // For a diff line list, optionally compute a unified-diff against a stored
62	  // baseline. We keep a per-file content cache from the last snapshot.
63	  unifiedDiff(relPath, beforeContent, afterContent) {
64	    // Simple line-based diff (LCS-light) — readable, no deps.
65	    const a = (beforeContent || '').split('\n');
66	    const b = (afterContent || '').split('\n');
67	    const out = [];
68	    let i = 0;
69	    let j = 0;
70	    while (i < a.length || j < b.length) {
71	      if (i < a.length && j < b.length && a[i] === b[j]) {
72	        out.push({ kind: 'eq', text: a[i] });
73	        i++;
74	        j++;
75	      } else {
76	        const findA = b.indexOf(a[i] ?? '�', j + 1);
77	        const findB = a.indexOf(b[j] ?? '�', i + 1);
78	        if (findA !== -1 && (findB === -1 || findA - j <= findB - i)) {
79	          while (j < findA) out.push({ kind: 'add', text: b[j++] });
80	        } else if (findB !== -1) {
81	          while (i < findB) out.push({ kind: 'del', text: a[i++] });
82	        } else {
83	          if (i < a.length) out.push({ kind: 'del', text: a[i++] });
84	          if (j < b.length) out.push({ kind: 'add', text: b[j++] });
85	        }
86	      }
87	    }
88	    return out;
89	  }
90	}
