101	const SCAN_IGNORE = new Set([
102	  'node_modules',
103	  '.git',
104	  '.DS_Store',
105	  'dist',
106	  'build',
107	  'coverage',
108	  '.venv',
109	  'venv',
110	  '__pycache__',
111	  '.next',
112	  '.nuxt',
113	  '.cache',
114	  '.turbo',
115	]);
116	const MAX_FILE_SIZE = 1_000_000;
117	
118	function scanWorkdir(root) {
119	  const out = {};
120	  function walk(dir) {
121	    let entries;
122	    try {
123	      entries = fs.readdirSync(dir, { withFileTypes: true });
124	    } catch {
125	      return;
126	    }
127	    for (const e of entries) {
128	      if (SCAN_IGNORE.has(e.name)) continue;
129	      const full = path.join(dir, e.name);
130	      if (e.isDirectory()) {
131	        walk(full);
132	      } else if (e.isFile()) {
133	        let stat;
134	        try {
135	          stat = fs.statSync(full);
136	        } catch {
137	          continue;
138	        }
139	        if (stat.size > MAX_FILE_SIZE) {
140	          // For large files, hash the size+mtime instead of contents.
141	          out[path.relative(root, full)] = {
142	            hash: `meta:${stat.size}:${stat.mtimeMs}`,
143	            size: stat.size,
144	            mtime: stat.mtimeMs,
145	          };
146	          continue;
147	        }
148	        try {
149	          const buf = fs.readFileSync(full);
150	          const hash = crypto.createHash('sha1').update(buf).digest('hex');
151	          out[path.relative(root, full)] = {
152	            hash,
153	            size: stat.size,
154	            mtime: stat.mtimeMs,
155	          };
156	        } catch {}
157	      }
158	    }
159	  }
160	  walk(root);
161	  return out;
162	}
163	
164	function isBinary(buf) {
165	  const len = Math.min(buf.length, 8000);
166	  for (let i = 0; i < len; i++) {
167	    if (buf[i] === 0) return true;
168	  }
169	  return false;
170	}
171	
172	// Capture file contents for diff against future state.
173	export function captureContents(workdir, relPaths) {
174	  const result = {};
175	  for (const rel of relPaths) {
176	    const full = path.join(workdir, rel);
177	    try {
178	      const stat = fs.statSync(full);
179	      if (stat.size > 500_000) {
180	        result[rel] = null;
181	        continue;
182	      }
183	      const buf = fs.readFileSync(full);
184	      if (isBinary(buf)) {
185	        result[rel] = null;
186	        continue;
187	      }
188	      result[rel] = buf.toString('utf8');
189	    } catch {
190	      result[rel] = null;
191	    }
192	  }
193	  return result;
194	}
