1	// Claude Code Console — single-process Node server.
2	// Serves a static UI (public/), exposes a small JSON API, and broadcasts
3	// session events over Server-Sent Events.
4	import http from 'node:http';
5	import fs from 'node:fs';
6	import path from 'node:path';
7	import { fileURLToPath } from 'node:url';
8	
9	import { SessionManager } from './src/sessionManager.js';
10	import { SessionStore } from './src/sessionStore.js';
11	import { PRESET_POLICIES, getPolicy } from './src/policyEngine.js';
12	import { scanStructure, annotateChanges } from './src/structure.js';
13	import { buildDesignGraph } from './src/designGraph.js';
14	import { buildCodeMap } from './src/codeMap.js';
15	import * as gitnexus from './src/gitnexus.js';
16	
17	const __dirname = path.dirname(fileURLToPath(import.meta.url));
18	const PUBLIC_DIR = path.join(__dirname, 'public');
19	const PORT = parseInt(process.env.PORT || '4477', 10);
20	
21	const DATA_DIR =
22	  process.env.CLAUDE_CONSOLE_DATA || path.join(__dirname, '.claude-console', 'sessions');
23	const store = new SessionStore({ dir: DATA_DIR });
24	const manager = new SessionManager({ store });
25	for (const persisted of store.loadAll()) {
26	  try {
27	    manager.hydrate(persisted);
28	  } catch (e) {
29	    console.error(`[startup] failed to hydrate ${persisted?.id}:`, e.message);
30	  }
31	}
32	const sseClients = new Set();
33	
34	manager.on('session:event', (payload) => broadcast('event', payload));
35	manager.on('session:updated', (payload) => broadcast('session:updated', payload));
36	manager.on('session:created', (payload) => broadcast('session:created', payload));
37	manager.on('session:removed', (payload) => broadcast('session:removed', payload));
38	
39	function broadcast(kind, data) {
40	  const line = `event: ${kind}\ndata: ${JSON.stringify(data)}\n\n`;
41	  for (const res of sseClients) {
42	    try {
43	      res.write(line);
44	    } catch {
45	      sseClients.delete(res);
46	    }
47	  }
48	}
49	
50	const MIME = {
51	  '.html': 'text/html; charset=utf-8',
52	  '.js': 'application/javascript; charset=utf-8',
53	  '.css': 'text/css; charset=utf-8',
54	  '.svg': 'image/svg+xml',
55	  '.ico': 'image/x-icon',
56	  '.png': 'image/png',
57	  '.json': 'application/json; charset=utf-8',
58	};
59	
60	const server = http.createServer(async (req, res) => {
61	  const reqUrl = new URL(req.url, `http://${req.headers.host || 'localhost'}`);
62	  const pathname = reqUrl.pathname;
63	  const parsed = { query: Object.fromEntries(reqUrl.searchParams) };
64	
65	  // CORS friendliness for local tools
66	  res.setHeader('Access-Control-Allow-Origin', '*');
67	  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, DELETE, OPTIONS');
68	  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
69	  if (req.method === 'OPTIONS') {
70	    res.writeHead(204);
71	    res.end();
72	    return;
73	  }
74	
75	  try {
76	    if (pathname === '/api/health') return json(res, 200, { ok: true });
77	    if (pathname === '/api/gitnexus/health' && req.method === 'GET') {
78	      const info = await gitnexus.isAvailable();
79	      return json(res, 200, info);
80	    }
81	    if (pathname === '/api/policies') return json(res, 200, { policies: PRESET_POLICIES });
82	    if (pathname === '/api/sessions' && req.method === 'GET')
83	      return json(res, 200, { sessions: manager.list() });
84	    if (pathname === '/api/sessions' && req.method === 'POST') {
85	      const body = await readJson(req);
86	      const s = manager.create(body);
87	      return json(res, 201, { session: s.summary() });
88	    }
89	    if (pathname === '/api/cwd' && req.method === 'GET')
90	      return json(res, 200, { cwd: process.cwd() });
91	
92	    if (pathname === '/api/events' && req.method === 'GET') {
93	      res.writeHead(200, {
94	        'Content-Type': 'text/event-stream; charset=utf-8',
95	        'Cache-Control': 'no-cache',
96	        Connection: 'keep-alive',
97	        'X-Accel-Buffering': 'no',
98	      });
99	      res.write(`event: hello\ndata: ${JSON.stringify({ ts: Date.now() })}\n\n`);
100	      sseClients.add(res);
101	      const ping = setInterval(() => {
102	        try {
103	          res.write(`event: ping\ndata: {}\n\n`);
104	        } catch {}
105	      }, 25_000);
106	      req.on('close', () => {
107	        clearInterval(ping);
108	        sseClients.delete(res);
109	      });
110	      return;
111	    }
112	
113	    // /api/sessions/:id...
114	    const match = pathname.match(/^\/api\/sessions\/([^/]+)(\/.*)?$/);
115	    if (match) {
116	      const id = match[1];
117	      const rest = match[2] || '';
