82	// Tools that ALWAYS need a human in the loop, regardless of policy. These
83	// exist precisely to ask the user something, so auto-approving them defeats
84	// their purpose — Claude would proceed without ever seeing the answer.
85	// Hardcoded as a global override so no policy preset can accidentally bypass.
86	const ALWAYS_MANUAL_TOOLS = new Set(['AskUserQuestion', 'ExitPlanMode']);
87	
88	// Evaluate a tool_use event against a policy.
89	// Returns { decision: 'auto'|'manual'|'reject', reason, rule }
90	export function evaluateToolUse(policy, toolUse, ctx = {}) {
91	  const toolName = toolUse.name || toolUse.tool || 'Unknown';
92	  const input = toolUse.input || {};
93	  const workdir = ctx.workdir;
94	
95	  if (ALWAYS_MANUAL_TOOLS.has(toolName)) {
96	    return {
97	      decision: 'manual',
98	      reason: toolName === 'AskUserQuestion'
99	        ? 'Claude 需要你回答问题（始终人工处理）'
100	        : '需要你确认计划（始终人工处理）',
101	      rule: { match: `tool:${toolName}`, decision: 'manual', reason: 'always-manual', builtin: true },
102	    };
103	  }
104	
105	  for (const rule of policy.rules) {
106	    const m = rule.match;
107	    if (!m.startsWith('tool:') && !m.startsWith('path:')) continue;
108	
109	    if (m === 'path:outside-workdir' && workdir) {
110	      const targets = collectPathTargets(input);
111	      const outside = targets.find((p) => !isInside(p, workdir));
112	      if (outside) {
113	        return { decision: rule.decision, reason: rule.reason + `（${outside}）`, rule };
114	      }
115	      continue;
116	    }
117	
118	    if (m.startsWith('tool:')) {
119	      const parts = m.slice('tool:'.length).split(':');
120	      const ruleTool = parts[0];
121	      const subPattern = parts.slice(1).join(':');
122	
123	      if (ruleTool !== '*' && ruleTool !== toolName) continue;
124	
125	      if (subPattern) {
126	        // Try matching against bash command
127	        const cmd = input.command || input.cmd || '';
128	        if (!cmd.toLowerCase().includes(subPattern.toLowerCase())) continue;
129	      }
130	      return { decision: rule.decision, reason: rule.reason, rule };
131	    }
132	  }
133	  return { decision: 'manual', reason: '没有命中规则，转人工确认', rule: null };
134	}
135	
136	function collectPathTargets(input) {
137	  const targets = [];
138	  for (const key of ['file_path', 'path', 'notebook_path', 'output_file']) {
139	    if (typeof input[key] === 'string') targets.push(input[key]);
140	  }
141	  return targets;
142	}
143	
144	function isInside(target, workdir) {
145	  if (!target) return true;
146	  let abs = target;
147	  if (!abs.startsWith('/')) abs = workdir.replace(/\/$/, '') + '/' + abs;
148	  const wd = workdir.replace(/\/$/, '');
149	  // Tolerate macOS symlink prefix /tmp <-> /private/tmp
150	  const candidates = [wd];
151	  if (wd.startsWith('/private/')) candidates.push(wd.slice('/private'.length));
152	  else candidates.push('/private' + wd);
153	  return candidates.some((c) => abs === c || abs.startsWith(c + '/'));
154	}
