286	function handleSessionEvent(evt) {
287	  if (!state.detail) return;
288	  state.detail.events.push(evt);
289	
290	  if (evt.type === 'tool:use' || evt.type === 'approval:resolved') {
291	    const tools = state.detail.tools;
292	    const i = tools.findIndex((t) => t.id === evt.id || t.id === evt.toolUseId);
293	    if (evt.type === 'tool:use') {
294	      if (i === -1) tools.push(evt);
295	      else tools[i] = evt;
296	    } else if (i !== -1) {
297	      tools[i].decision = evt.decision;
298	      tools[i].manualNote = evt.note;
299	      tools[i].manualResolution = evt.decision;

300	    }
301	  }
302	  if (evt.type === 'turn:changes' && evt.files && evt.files.length > 0) {
303	    state.detail.changes.push({ turnId: evt.turnId, timestamp: evt.ts, files: evt.files });
304	    state.structureCache = null;
305	    state.graphCache = null;
306	    state.codeMapCache = null;
307	    state.gitNexusCallGraph = null;
308	    state.gitNexusProcesses = null;
309	    state.gitNexusImpact = null;
310	    state.gitNexusStatus = null; // index becomes stale
311	  }
312	  if (evt.type === 'turn:start') {
313	    state.detail.turns.push({
314	      id: evt.turnId,
315	      prompt: evt.prompt,
316	      startedAt: evt.ts,
317	      endedAt: null,
318	      status: 'running',
319	      policyId: evt.policyId,
320	    });
321	  }
322	  if (evt.type === 'turn:end') {
323	    const t = state.detail.turns.find((x) => x.id === evt.turnId);
324	    if (t) {
325	      t.endedAt = evt.ts;
326	      t.status = evt.status;
327	    }
328	  }
329	  if (evt.type === 'approval:pending') {
330	    state.detail.pendingApprovals.push({
331	      id: evt.toolUseId,
332	      tool: evt.tool,
333	      input: evt.input,
334	      reason: evt.reason,
335	    });
336	  }
337	  if (evt.type === 'approval:resolved') {
338	    state.detail.pendingApprovals = state.detail.pendingApprovals.filter(
339	      (a) => a.id !== evt.toolUseId,
340	    );
341	  }
342	
343	  renderViewIfActive();
344	}
