626	function submitAskUserQuestion(id) {
627	  const card = $(`.approval-card[data-id="${id}"]`, $('#approvalPane'));
628	  if (!card) return;
629	  const lines = [];
630	  card.querySelectorAll('.auq-question').forEach((qEl) => {
631	    const head = qEl.querySelector('.auq-q-text')?.textContent?.trim() || '';
632	    const picked = Array.from(qEl.querySelectorAll('.auq-option.selected'))
633	      .map((b) => b.dataset.label)
634	      .filter(Boolean);
635	    const custom = qEl.querySelector('.auq-input')?.value?.trim() || '';
636	    const parts = [];
637	    if (picked.length) parts.push(picked.join(' / '));
638	    if (custom) parts.push(custom);
639	    if (parts.length) lines.push(`• ${head}\n  → ${parts.join(' | ')}`);
640	  });
641	  const noteText = readApprovalNote(id);
642	  if (noteText) lines.push(`备注：${noteText}`);
643	  const answer = lines.join('\n');
644	
645	  const promptInput = $('#promptInput');
646	  if (answer) {
647	    const existing = promptInput.value.trim();
648	    promptInput.value = existing ? `${existing}\n\n${answer}` : answer;
649	    promptInput.focus();
650	  }
651	  resolveApproval(id, 'approve', answer);
652	}
