// One-shot helper around the `claude` CLI. Spawns a fresh process with
// `--print --output-format stream-json --verbose`, parses the stream-json
// lines and resolves with the final assistant text (from the `result` event).
// Used by the memory distiller and the LLM decider — both want a short
// independent inference, not a long-lived conversation.
import { spawn } from 'node:child_process';

const DEFAULT_TIMEOUT_MS = 60_000;

// permissionMode: 'plan' is the safest sandbox — Claude can think and reply,
// but cannot execute Bash/Edit/Write etc. We use it for distillation and
// decider calls so a poisoned memory or transcript can't actually do anything.
export async function runClaudeOneShot({
  prompt,
  cwd,
  permissionMode = 'plan',
  signal,
  timeoutMs = DEFAULT_TIMEOUT_MS,
} = {}) {
  if (!prompt || typeof prompt !== 'string') {
    throw new Error('runClaudeOneShot: prompt is required');
  }

  const args = [
    '--print',
    '--output-format', 'stream-json',
    '--verbose',
    '--permission-mode', permissionMode,
    prompt,
  ];

  return new Promise((resolve, reject) => {
    let child;
    try {
      child = spawn('claude', args, {
        cwd: cwd || process.cwd(),
        env: { ...process.env, FORCE_COLOR: '0' },
        stdio: ['ignore', 'pipe', 'pipe'],
      });
    } catch (e) {
      return reject(new Error('spawn claude failed: ' + e.message));
    }

    let stdoutBuf = '';
    let stderrBuf = '';
    let finalText = '';
    let usage = null;
    let cost = null;
    let resultSubtype = null;
    let settled = false;

    const finish = (err, payload) => {
      if (settled) return;
      settled = true;
      if (timer) clearTimeout(timer);
      if (signal) signal.removeEventListener?.('abort', onAbort);
      try { child.stdout.removeAllListeners(); } catch {}
      try { child.stderr.removeAllListeners(); } catch {}
      if (err) reject(err); else resolve(payload);
    };

    const handleLine = (line) => {
      const trimmed = line.trim();
      if (!trimmed) return;
      let evt;
      try { evt = JSON.parse(trimmed); } catch { return; }
      if (evt.type === 'assistant' && evt.message && Array.isArray(evt.message.content)) {
        for (const block of evt.message.content) {
          if (block.type === 'text' && block.text) finalText += block.text;
        }
      } else if (evt.type === 'result') {
        resultSubtype = evt.subtype;
        usage = evt.usage || null;
        cost = evt.total_cost_usd ?? null;
        if (typeof evt.result === 'string' && evt.result) finalText = evt.result;
      }
    };

    child.stdout.on('data', (chunk) => {
      stdoutBuf += chunk.toString('utf8');
      let idx;
      while ((idx = stdoutBuf.indexOf('\n')) >= 0) {
        const line = stdoutBuf.slice(0, idx);
        stdoutBuf = stdoutBuf.slice(idx + 1);
        handleLine(line);
      }
    });

    child.stderr.on('data', (chunk) => { stderrBuf += chunk.toString('utf8'); });

    child.on('error', (err) => finish(new Error('claude error: ' + err.message)));

    child.on('close', (code) => {
      if (stdoutBuf.trim()) handleLine(stdoutBuf);
      if (code !== 0 && !finalText) {
        return finish(new Error(`claude exited ${code}: ${stderrBuf.trim().slice(0, 500)}`));
      }
      finish(null, { text: finalText, usage, cost, subtype: resultSubtype });
    });

    const timer = setTimeout(() => {
      try { child.kill('SIGTERM'); } catch {}
      finish(new Error(`claude timed out after ${timeoutMs}ms`));
    }, timeoutMs);
    if (typeof timer.unref === 'function') timer.unref();

    const onAbort = () => {
      try { child.kill('SIGTERM'); } catch {}
      finish(new Error('aborted'));
    };
    if (signal) {
      if (signal.aborted) return onAbort();
      signal.addEventListener?.('abort', onAbort, { once: true });
    }
  });
}

// Helper: extract the first JSON object/array from a free-text response.
// LLMs sometimes wrap output in markdown fences or add prose; we pull out
// the first balanced {...} or [...] and parse it.
export function extractJson(text) {
  if (!text || typeof text !== 'string') return null;
  const trimmed = text.trim();
  // Try direct parse first.
  try { return JSON.parse(trimmed); } catch {}
  // Strip markdown code fences.
  const fence = trimmed.match(/```(?:json)?\s*([\s\S]+?)\s*```/);
  if (fence) {
    try { return JSON.parse(fence[1]); } catch {}
  }
  // Find the first balanced JSON object/array by counting braces.
  for (const open of ['{', '[']) {
    const start = trimmed.indexOf(open);
    if (start === -1) continue;
    const close = open === '{' ? '}' : ']';
    let depth = 0;
    let inStr = false;
    let esc = false;
    for (let i = start; i < trimmed.length; i++) {
      const ch = trimmed[i];
      if (esc) { esc = false; continue; }
      if (ch === '\\') { esc = true; continue; }
      if (ch === '"') { inStr = !inStr; continue; }
      if (inStr) continue;
      if (ch === open) depth++;
      else if (ch === close) {
        depth--;
        if (depth === 0) {
          const slice = trimmed.slice(start, i + 1);
          try { return JSON.parse(slice); } catch { break; }
        }
      }
    }
  }
  return null;
}

// MemoryStore — owns persistence of the global memory file.
// Mirrors SessionStore's pattern: debounced atomic writes, version-validated,
// corrupt files renamed rather than crashing the server.
import fs from 'node:fs';
import path from 'node:path';
import { randomUUID } from 'node:crypto';

const VERSION = 1;
const DEBOUNCE_MS = 200;

export class MemoryStore {
  constructor({ file }) {
    this.file = file;
    fs.mkdirSync(path.dirname(file), { recursive: true });
    this.entries = []; // in-memory canonical state
    this._timer = null;
    this._loaded = false;
  }

  load() {
    if (this._loaded) return this.entries;
    this._loaded = true;
    if (!fs.existsSync(this.file)) {
      this.entries = [];
      return this.entries;
    }
    try {
      const raw = fs.readFileSync(this.file, 'utf8');
      const payload = JSON.parse(raw);
      if (this._validate(payload)) {
        this.entries = Array.isArray(payload.entries) ? payload.entries : [];
      } else {
        this._markCorrupt();
        this.entries = [];
      }
    } catch {
      this._markCorrupt();
      this.entries = [];
    }
    return this.entries;
  }

  scheduleSave() {
    if (this._timer) return;
    this._timer = setTimeout(() => {
      this._timer = null;
      this._writeNow();
    }, DEBOUNCE_MS);
    if (typeof this._timer.unref === 'function') this._timer.unref();
  }

  flush() {
    if (this._timer) {
      clearTimeout(this._timer);
      this._timer = null;
    }
    this._writeNow();
  }

  _writeNow() {
    const payload = { version: VERSION, entries: this.entries };
    const tmp = this.file + '.tmp';
    try {
      fs.writeFileSync(tmp, JSON.stringify(payload, null, 2));
      fs.renameSync(tmp, this.file);
    } catch (e) {
      console.error('[memoryStore] write failed:', e.message);
      try { fs.unlinkSync(tmp); } catch {}
    }
  }

  _validate(payload) {
    return payload && payload.version === VERSION && Array.isArray(payload.entries);
  }

  _markCorrupt() {
    try {
      fs.renameSync(this.file, this.file + '.corrupt.' + Date.now());
    } catch {}
  }

  // Mutators are thin — engine functions do the work, store records the
  // change and triggers a save.
  upsert(entry) {
    const i = this.entries.findIndex((e) => e.id === entry.id);
    if (i === -1) this.entries.push(entry);
    else this.entries[i] = entry;
    this.scheduleSave();
    return entry;
  }

  remove(id) {
    const before = this.entries.length;
    this.entries = this.entries.filter((e) => e.id !== id);
    if (this.entries.length !== before) this.scheduleSave();
    return before !== this.entries.length;
  }

  replaceAll(entries) {
    this.entries = entries;
    this.scheduleSave();
  }
}

export function newMemoryId(prefix = 'm') {
  return `${prefix}_${Date.now().toString(36)}_${randomUUID().slice(0, 8)}`;
}

// memoryEngine — pure functions that turn raw session events into normalized
// memory entries (`habit` / `experience`) and look them up at decision time.
// No I/O, no state — receives `entries` arrays and the inputs it needs.
import { createHash } from 'node:crypto';
import path from 'node:path';

import { newMemoryId } from './memoryStore.js';

// ---------- Hashing & redaction ----------

export function hashWorkdir(workdir) {
  if (!workdir) return null;
  return createHash('sha1').update(workdir).digest('hex').slice(0, 12);
}

const SECRET_PATTERNS = [
  // KEY/TOKEN/SECRET/PASSWORD-shaped variable assignments.
  { re: /([A-Za-z0-9_]*(?:KEY|TOKEN|SECRET|PASSWORD|PWD|PASS)[A-Za-z0-9_]*\s*[=:]\s*)(\S+)/gi,
    repl: '$1<redacted>' },
  // Common API token shapes (anchored — must look like a real token).
  { re: /sk-[A-Za-z0-9_-]{20,}/g, repl: '<redacted>' },
  { re: /ghp_[A-Za-z0-9_-]{20,}/g, repl: '<redacted>' },
  { re: /AKIA[A-Z0-9]{12,}/g, repl: '<redacted>' },
  // Bearer auth.
  { re: /(Authorization\s*:\s*Bearer\s+)\S+/gi, repl: '$1<redacted>' },
  // CLI flag forms.
  { re: /(--password=|--token=|--api[-_]key=)\S+/gi, repl: '$1<redacted>' },
];

export function redactString(s) {
  if (typeof s !== 'string' || !s) return s;
  let out = s;
  for (const p of SECRET_PATTERNS) out = out.replace(p.re, p.repl);
  return out;
}

const MAX_FIELD = 4096;
const MAX_TOTAL = 8192;

export function redactInput(input) {
  if (input == null) return input;
  if (typeof input === 'string') {
    const r = redactString(input);
    return r.length > MAX_FIELD ? r.slice(0, MAX_FIELD) + '…' : r;
  }
  if (Array.isArray(input)) return input.map(redactInput);
  if (typeof input === 'object') {
    const out = {};
    for (const [k, v] of Object.entries(input)) out[k] = redactInput(v);
    const serialized = JSON.stringify(out);
    if (serialized.length > MAX_TOTAL) {
      return { _truncated: true, _size: serialized.length };
    }
    return out;
  }
  return input;
}

// ---------- keySignature ----------

export function keyFor(tool, input, workdir) {
  const safeInput = redactInput(input);
  const kind = tool === 'AskUserQuestion' ? 'auq' : 'tool';
  let keySignature;

  if (tool === 'Bash') {
    keySignature = bashKey(safeInput);
  } else if (tool === 'Read') {
    keySignature = readKey(safeInput, workdir);
  } else if (tool === 'Edit' || tool === 'Write') {
    keySignature = editWriteKey(tool, safeInput, workdir);
  } else if (tool === 'WebFetch') {
    keySignature = webfetchKey(safeInput);
  } else if (tool === 'WebSearch') {
    keySignature = 'websearch:*';
  } else if (tool === 'AskUserQuestion') {
    // For AUQ the key is set per-answer in the extractor; here just return the question hash.
    keySignature = `auq:${stableHash(safeInput).slice(0, 16)}`;
  } else if (tool === 'Glob' || tool === 'Grep') {
    keySignature = `${tool.toLowerCase()}:*`;
  } else {
    keySignature = `${tool.toLowerCase()}:${stableHash(safeInput).slice(0, 12)}`;
  }

  return { kind, keySignature, inputSample: safeInput };
}

function bashKey(input) {
  const cmd = (input?.command || input?.cmd || '').trim();
  if (!cmd) return 'bash:<empty>';
  // Strip everything after `--` (script-level args) for matching purposes.
  const cutAt = cmd.indexOf(' -- ');
  const head = cutAt >= 0 ? cmd.slice(0, cutAt) : cmd;
  const tokens = head.split(/\s+/).filter(Boolean);
  let arg0 = tokens[0] || '';
  // Inline env-var assignments (KEY=val) come before the actual command — skip them.
  let i = 0;
  while (i < tokens.length && /^[A-Z_][A-Z0-9_]*=/.test(tokens[i])) i++;
  if (i > 0) arg0 = tokens[i] || '';
  // Replace bare paths with placeholder.
  if (/^\.{0,2}\//.test(arg0)) arg0 = '<path>';
  arg0 = arg0.toLowerCase();
  // Pick second token if it's a subcommand (no leading dash, no path char).
  const arg1 = tokens[i + 1];
  if (arg1 && !arg1.startsWith('-') && !/[/$`]/.test(arg1)) {
    return `bash:${arg0}:${arg1.toLowerCase()}`;
  }
  return `bash:${arg0}`;
}

function readKey(input, workdir) {
  const p = input?.file_path || input?.path || '';
  if (!p) return 'read:<empty>';
  const base = path.basename(p);
  if (/(^|\.)env(\.|$)/.test(base) || /\.key$/.test(base) || /^id_rsa/.test(base)) {
    return 'read:env-like';
  }
  const ext = (path.extname(p) || '').toLowerCase().replace('.', '') || 'noext';
  return `read:${ext}`;
}

function editWriteKey(tool, input, workdir) {
  const p = input?.file_path || input?.path || input?.notebook_path || '';
  if (!p) return `${tool.toLowerCase()}:<empty>`;
  const ext = (path.extname(p) || '').toLowerCase().replace('.', '') || 'noext';
  let topDir = '';
  try {
    if (workdir) {
      const rel = path.relative(workdir, p);
      if (rel && !rel.startsWith('..')) topDir = rel.split(path.sep)[0];
    }
  } catch {}
  if (!topDir) topDir = '<root>';
  return `${tool.toLowerCase()}:${ext}:${topDir}`;
}

function webfetchKey(input) {
  const url = input?.url || '';
  try {
    const u = new URL(url);
    return `webfetch:${u.host}`;
  } catch {
    return 'webfetch:<invalid>';
  }
}

function stableHash(obj) {
  return createHash('sha1')
    .update(JSON.stringify(obj, Object.keys(obj || {}).sort()))
    .digest('hex');
}

// ---------- AUQ key for answer-tracking ----------

export function auqAnswerKey(question, pickedLabel) {
  const qhash = createHash('sha1').update(String(question || '')).digest('hex').slice(0, 16);
  const label = String(pickedLabel || '').toLowerCase().slice(0, 64);
  return `auq:${qhash}:${label}`;
}

// ---------- Lookup ----------

export function lookupHabit(entries, { keySignature, workdirHash }) {
  if (!keySignature) return null;
  // Prefer workdir-scoped match.
  for (const e of entries) {
    if (e.kind !== 'habit') continue;
    if (e.keySignature !== keySignature) continue;
    if (e.scope === 'workdir' && e.workdirHash === workdirHash) return e;
  }
  for (const e of entries) {
    if (e.kind !== 'habit') continue;
    if (e.keySignature !== keySignature) continue;
    if (e.scope === 'global') return e;
  }
  return null;
}

// ---------- Fast-path auto-decide ----------

const FAST_PATH_DOM_THRESHOLD = 5;
const NINETY_DAYS = 90 * 24 * 3600 * 1000;
const THIRTY_DAYS = 30 * 24 * 3600 * 1000;

export function shouldAutoApply(entry, now = Date.now()) {
  if (!entry || entry.kind !== 'habit') return null;
  if (entry.frozen) return null;
  const counts = entry.counts || { approve: 0, reject: 0 };
  const dom = Math.max(counts.approve, counts.reject);
  const sub = Math.min(counts.approve, counts.reject);
  if (dom < FAST_PATH_DOM_THRESHOLD || sub > 0) return null;
  if (!entry.lastTs || now - entry.lastTs > NINETY_DAYS) return null;
  if (entry.lastOpposingTs && now - entry.lastOpposingTs <= THIRTY_DAYS) return null;
  return counts.approve >= counts.reject ? 'approve' : 'reject';
}

// ---------- Merge / commit ----------

// Merge a candidate habit (from extractor) into the entries array.
// If a same-key+same-scope entry exists, increment counts and append session
// history. Otherwise create a new entry.
export function mergeHabit(entries, candidate, now = Date.now()) {
  const found = entries.find(
    (e) => e.kind === 'habit' &&
           e.keySignature === candidate.keySignature &&
           e.scope === candidate.scope &&
           (e.scope === 'global' || e.workdirHash === candidate.workdirHash),
  );
  if (!found) {
    const created = {
      id: newMemoryId('h'),
      kind: 'habit',
      scope: candidate.scope,
      workdirHash: candidate.workdirHash || null,
      tool: candidate.tool,
      keySignature: candidate.keySignature,
      inputSample: candidate.inputSample,
      counts: { approve: candidate.counts?.approve || 0, reject: candidate.counts?.reject || 0 },
      lastDecision: candidate.lastDecision || null,
      lastNote: candidate.lastNote || '',
      lastTs: candidate.lastTs || now,
      lastOpposingTs: null,
      sessions: candidate.sessions ? candidate.sessions.slice(-20) : [],
      frozen: false,
      redactionVersion: 1,
      createdAt: now,
      updatedAt: now,
    };
    entries.push(created);
    return { entry: created, action: 'created' };
  }
  // Existing — sum counts, append sessions, update timestamps.
  const prevDom = found.lastDecision;
  found.counts.approve += candidate.counts?.approve || 0;
  found.counts.reject += candidate.counts?.reject || 0;
  if (candidate.lastDecision) found.lastDecision = candidate.lastDecision;
  if (candidate.lastNote) found.lastNote = candidate.lastNote;
  found.lastTs = candidate.lastTs || now;
  if (prevDom && candidate.lastDecision && prevDom !== candidate.lastDecision) {
    found.lastOpposingTs = found.lastTs;
  }
  if (candidate.sessions && candidate.sessions.length) {
    found.sessions = [...(found.sessions || []), ...candidate.sessions].slice(-20);
  }
  found.updatedAt = now;
  return { entry: found, action: 'updated' };
}

export function mergeExperience(entries, candidate, now = Date.now()) {
  const created = {
    id: newMemoryId('e'),
    kind: 'experience',
    scope: candidate.scope || 'workdir',
    workdirHash: candidate.workdirHash || null,
    title: String(candidate.title || '').slice(0, 200),
    body: redactString(String(candidate.body || '').slice(0, 4000)),
    tags: Array.isArray(candidate.tags) ? candidate.tags.slice(0, 10).map(String) : [],
    triggers: {
      tools: Array.isArray(candidate.triggers?.tools) ? candidate.triggers.tools.map(String).slice(0, 10) : [],
      pathGlobs: Array.isArray(candidate.triggers?.pathGlobs) ? candidate.triggers.pathGlobs.map(String).slice(0, 10) : [],
      keywords: Array.isArray(candidate.triggers?.keywords) ? candidate.triggers.keywords.map(String).slice(0, 20) : [],
    },
    weight: typeof candidate.weight === 'number' ? candidate.weight : 1,
    sourceSession: candidate.sourceSession || null,
    sourceTurn: candidate.sourceTurn || null,
    confirmed: candidate.confirmed !== false,
    enabledForInjection: candidate.enabledForInjection !== false,
    enabledForDecider: candidate.enabledForDecider !== false,
    createdAt: now,
    updatedAt: now,
  };
  entries.push(created);
  return { entry: created, action: 'created' };
}

// ---------- Filtering helpers (used by retriever) ----------

export function relevantHabits(entries, { workdirHash, tool }) {
  return entries.filter(
    (e) => e.kind === 'habit' &&
      (e.scope === 'global' || e.workdirHash === workdirHash) &&
      (!tool || e.tool === tool),
  );
}

export function allExperiences(entries, { workdirHash } = {}) {
  return entries.filter(
    (e) => e.kind === 'experience' && e.confirmed &&
      (!workdirHash || e.scope === 'global' || e.workdirHash === workdirHash),
  );
}

// habitExtractor — turns the events of a single completed turn into a list
// of candidate `habit` entries. Pure function; the user reviews the output
// before anything is persisted.
import { keyFor, hashWorkdir, auqAnswerKey, redactInput } from './memoryEngine.js';

export function extractHabits({ session, turnId, scope = 'workdir' }) {
  if (!session || !turnId) return [];
  const events = Array.isArray(session.events) ? session.events : [];
  const tools = Array.isArray(session.tools) ? session.tools : [];
  const toolById = new Map(tools.map((t) => [t.id, t]));
  const workdirHash = scope === 'workdir' ? hashWorkdir(session.workdir) : null;

  // Walk events: accumulate decisions per turn. Resolved approvals + tool:use
  // entries with decision==='auto'/'reject' both count, but we focus on user-
  // resolved approvals (the strongest signal of preference).
  const turnEvents = events.filter((e) => e.turnId === turnId || (e.type === 'turn:end' && e.turnId === turnId));
  const candidates = new Map(); // keySignature → candidate

  for (const evt of turnEvents) {
    if (evt.type === 'approval:resolved') {
      const tool = toolById.get(evt.toolUseId);
      if (!tool) continue;
      if (tool.tool === 'AskUserQuestion') {
        // Special-case AUQ: emit one habit per (question, picked-label).
        emitAUQAnswers({ tool, evt, candidates, workdirHash, scope, turnId, session });
      } else {
        emitToolHabit({ tool, evt, candidates, workdirHash, scope, turnId, session });
      }
    }
  }

  return Array.from(candidates.values());
}

function emitToolHabit({ tool, evt, candidates, workdirHash, scope, turnId, session }) {
  const { keySignature, inputSample } = keyFor(tool.tool, tool.input, session.workdir);
  const decision = evt.decision === 'reject' ? 'reject' : 'approve';
  let cand = candidates.get(keySignature);
  if (!cand) {
    cand = {
      tool: tool.tool,
      keySignature,
      inputSample,
      scope,
      workdirHash,
      counts: { approve: 0, reject: 0 },
      lastDecision: decision,
      lastNote: evt.note || '',
      lastTs: evt.ts || Date.now(),
      sessions: [],
    };
    candidates.set(keySignature, cand);
  }
  cand.counts[decision] = (cand.counts[decision] || 0) + 1;
  cand.lastDecision = decision;
  if (evt.note) cand.lastNote = evt.note;
  cand.lastTs = evt.ts || cand.lastTs;
  cand.sessions.push({
    sessionId: session.id,
    turnId,
    ts: evt.ts || Date.now(),
    decision,
    policyId: session.policyId,
  });
}

function emitAUQAnswers({ tool, evt, candidates, workdirHash, scope, turnId, session }) {
  // The note is a free-form text we asked the UI to assemble. We try to also
  // parse a `auqAnswers` array if the client sent it; otherwise we emit a
  // single habit keyed on the question+note hash so at least the *question*
  // is remembered.
  const answers = Array.isArray(evt.auqAnswers) ? evt.auqAnswers : null;
  const questionsArr = Array.isArray(tool.input?.questions) ? tool.input.questions : [];
  const sources = answers || inferAUQAnswers(tool.input, evt.note);

  for (const ans of sources) {
    const question = ans.question || (questionsArr[ans.qIndex]?.question) || '';
    const picks = Array.isArray(ans.picked) ? ans.picked : [];
    if (!question || picks.length === 0) continue;
    for (const label of picks) {
      const keySignature = auqAnswerKey(question, label);
      let cand = candidates.get(keySignature);
      if (!cand) {
        cand = {
          tool: 'AskUserQuestion',
          keySignature,
          inputSample: redactInput({ question, picked: label }),
          scope,
          workdirHash,
          counts: { approve: 0, reject: 0 },
          lastDecision: 'approve',
          lastNote: evt.note || '',
          lastTs: evt.ts || Date.now(),
          sessions: [],
        };
        candidates.set(keySignature, cand);
      }
      cand.counts.approve = (cand.counts.approve || 0) + 1;
      cand.lastDecision = 'approve';
      cand.lastTs = evt.ts || cand.lastTs;
      cand.sessions.push({
        sessionId: session.id,
        turnId,
        ts: evt.ts || Date.now(),
        decision: 'approve',
        policyId: session.policyId,
      });
    }
  }
}

// Best-effort parse of the textified note the UI assembles in submitAskUserQuestion:
//   • <question text>
//     → <picked / picked> | <custom>
function inferAUQAnswers(input, note) {
  if (!note || typeof note !== 'string') return [];
  const questions = Array.isArray(input?.questions) ? input.questions : [];
  const out = [];
  const lines = note.split('\n');
  let curQ = null;
  for (const line of lines) {
    const m = line.match(/^•\s*(.+)$/);
    if (m) {
      curQ = m[1].trim();
      continue;
    }
    const a = line.match(/^\s*→\s*(.+)$/);
    if (a && curQ) {
      const arrowPart = a[1].split('|')[0].trim();
      const picked = arrowPart.split('/').map((s) => s.trim()).filter(Boolean);
      // Match against the actual options (so we only sediment chip picks, not free text).
      const realQ = questions.find((q) => (q.question || '').trim() === curQ);
      const validLabels = new Set((realQ?.options || []).map((o) => (o.label || '').trim()));
      const validPicks = picked.filter((p) => validLabels.has(p));
      if (validPicks.length > 0) {
        out.push({ question: curQ, picked: validPicks });
      }
      curQ = null;
    }
  }
  return out;
}

// memoryDistiller — invokes a one-shot `claude` call to extract qualitative
// "experience" memories from the events of a finished turn. Returns candidate
// experiences (NOT persisted — the user reviews them first).
import { runClaudeOneShot, extractJson } from './claudeRunner.js';
import { redactString } from './memoryEngine.js';

const MAX_TURN_LOG_BYTES = 12_000;

export async function distillExperiences({ session, turnId, signal, timeoutMs = 60_000 } = {}) {
  if (!session || !turnId) return { items: [], error: 'missing session/turnId' };
  const turn = session.turns?.find((t) => t.id === turnId);
  if (!turn) return { items: [], error: `turn ${turnId} not found` };

  const transcript = buildTranscript({ session, turnId });
  const prompt = buildPrompt({ session, turn, transcript });

  let result;
  try {
    result = await runClaudeOneShot({
      prompt,
      cwd: session.workdir,
      permissionMode: 'plan',
      signal,
      timeoutMs,
    });
  } catch (e) {
    return { items: [], error: e.message };
  }

  const parsed = extractJson(result.text || '');
  if (!parsed || !Array.isArray(parsed.items)) {
    return { items: [], error: 'failed to parse JSON from model output', raw: result.text };
  }

  const items = parsed.items
    .filter((it) => it && typeof it === 'object' && it.title && it.body)
    .map((it) => ({
      title: redactString(String(it.title)).slice(0, 200),
      body: redactString(String(it.body)).slice(0, 4000),
      tags: Array.isArray(it.tags) ? it.tags.map(String).slice(0, 10) : [],
      triggers: {
        tools: Array.isArray(it.triggers?.tools) ? it.triggers.tools.map(String).slice(0, 10) : [],
        pathGlobs: Array.isArray(it.triggers?.pathGlobs) ? it.triggers.pathGlobs.map(String).slice(0, 10) : [],
        keywords: Array.isArray(it.triggers?.keywords) ? it.triggers.keywords.map(String).slice(0, 20) : [],
      },
    }))
    .slice(0, 6);

  return { items, error: null, usage: result.usage, cost: result.cost };
}

function buildPrompt({ session, turn, transcript }) {
  return [
    '你是经验提炼助手。下面是用户与 Claude Code 的一次任务会话日志（已脱敏）。',
    '请从中提炼可在未来复用的"经验记忆"。',
    '',
    '【输出要求】',
    '- 严格 JSON，不要 markdown 代码块包裹，不要任何解释文字。',
    '- 每条经验 ≤3 段、第一人称中文，聚焦：用户偏好 / 避坑要点 / 可复用思路。',
    '- 不要复述具体代码，要写出"为什么这样做、下次怎么做"。',
    '- 没有值得沉淀的内容时返回 {"items":[]}。',
    '',
    '【格式】',
    '{ "items": [',
    '  { "title": "...",',
    '    "body": "...",',
    '    "tags": ["..."],',
    '    "triggers": { "tools":["..."], "pathGlobs":["..."], "keywords":["..."] } },',
    '  ...',
    '] }',
    '',
    `【工程】 workdir=${session.workdir}  policy=${session.policyId}`,
    `【本轮提示】 ${redactString(String(turn.prompt || '').slice(0, 1000))}`,
    '【会话日志】',
    transcript,
    '',
    '现在请输出 JSON：',
  ].join('\n');
}

function buildTranscript({ session, turnId }) {
  const events = Array.isArray(session.events) ? session.events : [];
  const lines = [];
  let used = 0;
  for (const e of events) {
    if (e.turnId !== turnId) continue;
    let line = null;
    if (e.type === 'assistant:text') line = `[assistant] ${truncate(e.text, 500)}`;
    else if (e.type === 'tool:use') line = `[tool ${e.tool}] decision=${e.decision} reason=${truncate(e.reason || '', 80)} input=${truncate(JSON.stringify(e.input || {}), 200)}`;
    else if (e.type === 'tool:result') line = `[result] ${e.isError ? '(error) ' : ''}${truncate(e.content || '', 300)}`;
    else if (e.type === 'approval:resolved') line = `[approval] ${e.toolUseId} -> ${e.decision}${e.note ? ' note=' + truncate(e.note, 200) : ''}`;
    else if (e.type === 'turn:result' && e.result) line = `[final] ${truncate(e.result, 500)}`;
    else if (e.type === 'turn:changes' && Array.isArray(e.files) && e.files.length) {
      line = `[changes] ${e.files.map((f) => `${f.kind}:${f.relPath}`).join(', ')}`;
    }
    if (!line) continue;
    line = redactString(line);
    if (used + line.length > MAX_TURN_LOG_BYTES) {
      lines.push('… (日志已截断)');
      break;
    }
    used += line.length + 1;
    lines.push(line);
  }
  return lines.join('\n') || '(空)';
}

function truncate(s, n) {
  if (s == null) return '';
  const str = String(s);
  return str.length > n ? str.slice(0, n) + '…' : str;
}

// memoryRetriever — finds experience memories relevant to a prompt or
// approval context. Pure function; takes the entries array, returns a
// scored, filtered list.
import path from 'node:path';

import { hashWorkdir, allExperiences, relevantHabits } from './memoryEngine.js';

const DEFAULT_LIMIT = 5;

// Find experiences that should be injected into a new prompt.
export function relevantForPrompt(entries, { workdir, prompt, modifiedPaths = [] } = {}) {
  const workdirHash = hashWorkdir(workdir);
  const candidates = allExperiences(entries, { workdirHash });
  const promptLower = String(prompt || '').toLowerCase();
  const scored = [];
  for (const e of candidates) {
    if (e.enabledForInjection === false) continue;
    let score = 0;
    const triggers = e.triggers || {};
    if (Array.isArray(triggers.keywords)) {
      for (const k of triggers.keywords) {
        if (k && promptLower.includes(String(k).toLowerCase())) score += 3;
      }
    }
    if (Array.isArray(triggers.pathGlobs) && modifiedPaths.length) {
      for (const g of triggers.pathGlobs) {
        if (modifiedPaths.some((p) => simpleGlobMatch(g, p))) score += 2;
      }
    }
    if (Array.isArray(e.tags) && e.tags.length) {
      // Soft boost for any tag overlap with prompt tokens.
      for (const t of e.tags) {
        if (t && promptLower.includes(String(t).toLowerCase())) score += 1;
      }
    }
    score *= e.weight || 1;
    if (score >= 2) scored.push({ entry: e, score });
  }
  scored.sort((a, b) => b.score - a.score);
  return scored.slice(0, DEFAULT_LIMIT).map((s) => s.entry);
}

// Find memories relevant to a specific tool-use decision (for the decider).
export function relevantForDecision(entries, { workdir, tool, input, prompt }) {
  const workdirHash = hashWorkdir(workdir);
  const habits = relevantHabits(entries, { workdirHash, tool }).slice(0, 5);
  const targetPaths = collectPaths(input);
  const exps = allExperiences(entries, { workdirHash })
    .filter((e) => e.enabledForDecider !== false)
    .map((e) => ({ entry: e, score: scoreExperienceForDecision(e, { tool, paths: targetPaths, prompt }) }))
    .filter((s) => s.score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, 3)
    .map((s) => s.entry);
  return { habits, experiences: exps };
}

function scoreExperienceForDecision(e, { tool, paths, prompt }) {
  let score = 0;
  const triggers = e.triggers || {};
  if (Array.isArray(triggers.tools) && tool && triggers.tools.includes(tool)) score += 2;
  if (Array.isArray(triggers.pathGlobs) && paths.length) {
    for (const g of triggers.pathGlobs) {
      if (paths.some((p) => simpleGlobMatch(g, p))) score += 2;
    }
  }
  if (Array.isArray(triggers.keywords) && prompt) {
    const lower = String(prompt).toLowerCase();
    for (const k of triggers.keywords) {
      if (k && lower.includes(String(k).toLowerCase())) score += 1;
    }
  }
  return score * (e.weight || 1);
}

function collectPaths(input) {
  if (!input || typeof input !== 'object') return [];
  const out = [];
  for (const key of ['file_path', 'path', 'notebook_path', 'output_file']) {
    if (typeof input[key] === 'string') out.push(input[key]);
  }
  return out;
}

// Minimal glob matcher: supports `*` (segment wildcard) and `**` (any depth).
// We intentionally avoid pulling in a full glob lib — these patterns are
// user-typed in the memory UI and a small predictable matcher is fine.
export function simpleGlobMatch(pattern, target) {
  if (!pattern || !target) return false;
  // Normalize.
  const p = pattern.replace(/\\/g, '/');
  const t = target.replace(/\\/g, '/');
  // Fast literal substring: helpful when user types "src/foo".
  if (!/[*?]/.test(p)) return t.includes(p);
  // Convert to regex.
  const re = '^' + p
    .replace(/[.+^${}()|[\]\\]/g, '\\$&')
    .replace(/\*\*/g, '§§')
    .replace(/\*/g, '[^/]*')
    .replace(/§§/g, '.*')
    .replace(/\?/g, '[^/]') + '$';
  try {
    return new RegExp(re).test(t);
  } catch {
    return false;
  }
}

// deciderQueue — bounds the cost/concurrency of LLM-based decision calls.
// The console can run many sessions; an unhinged Claude could fire dozens of
// tool calls per turn. We protect against that with two limits:
//   - per-turn cap: refuses to invoke the decider after N calls in one turn
//   - global concurrency: at most M in-flight decider promises across sessions

const DEFAULT_GLOBAL_CONCURRENCY = 3;
const DEFAULT_PER_TURN_CAP = 20;

export class DeciderQueue {
  constructor({ globalConcurrency = DEFAULT_GLOBAL_CONCURRENCY, perTurnCap = DEFAULT_PER_TURN_CAP } = {}) {
    this.globalConcurrency = globalConcurrency;
    this.perTurnCap = perTurnCap;
    this._inFlight = 0;
    this._queue = []; // {fn, resolve, reject}
    this._turnCounts = new Map(); // `${sessionId}|${turnId}` -> count
    this._abortControllers = new Map(); // toolUseId -> AbortController
  }

  // Returns:
  //   { ok: true, run(fn): Promise }    — caller may run
  //   { ok: false, reason: 'quota' }    — per-turn quota exhausted
  acquire({ sessionId, turnId, toolUseId }) {
    const key = `${sessionId}|${turnId}`;
    const cur = this._turnCounts.get(key) || 0;
    if (cur >= this.perTurnCap) {
      return { ok: false, reason: 'quota' };
    }
    this._turnCounts.set(key, cur + 1);
    return {
      ok: true,
      run: (fn) => this._enqueue(fn, toolUseId),
    };
  }

  _enqueue(fn, toolUseId) {
    return new Promise((resolve, reject) => {
      this._queue.push({ fn, resolve, reject, toolUseId });
      this._drain();
    });
  }

  _drain() {
    while (this._inFlight < this.globalConcurrency && this._queue.length > 0) {
      const job = this._queue.shift();
      this._inFlight++;
      const ac = new AbortController();
      if (job.toolUseId) this._abortControllers.set(job.toolUseId, ac);
      Promise.resolve()
        .then(() => job.fn(ac.signal))
        .then((v) => job.resolve(v), (e) => job.reject(e))
        .finally(() => {
          this._inFlight--;
          if (job.toolUseId) this._abortControllers.delete(job.toolUseId);
          this._drain();
        });
    }
  }

  // External cancellation (user clicked "我自己决定").
  cancel(toolUseId) {
    const ac = this._abortControllers.get(toolUseId);
    if (ac) ac.abort();
    // Remove pending queue entries for the same toolUseId.
    this._queue = this._queue.filter((j) => {
      if (j.toolUseId === toolUseId) {
        j.reject(new Error('user-cancelled'));
        return false;
      }
      return true;
    });
  }

  // Called when a turn ends — frees the per-turn counter so it can be reused
  // (no actual benefit since IDs are unique, but keeps the map bounded).
  resetTurn(sessionId, turnId) {
    this._turnCounts.delete(`${sessionId}|${turnId}`);
  }

  abortAll() {
    for (const ac of this._abortControllers.values()) {
      try { ac.abort(); } catch {}
    }
    this._abortControllers.clear();
    for (const j of this._queue) j.reject(new Error('shutdown'));
    this._queue = [];
  }
}

// memoryDecider — given a manual approval point (tool call or AskUserQuestion),
// asks an independent `claude -p` instance to pick the option most consistent
// with the user's accumulated memory. Returns a strict verdict with confidence;
// the caller decides whether to act on it or escalate to the human.
import { runClaudeOneShot, extractJson } from './claudeRunner.js';
import { redactInput, redactString } from './memoryEngine.js';
import { relevantForDecision } from './memoryRetriever.js';

const DEFAULT_TIMEOUT_MS = 10_000;

// Decide for a normal tool approval (returns approve | reject | uncertain).
export async function decideToolApproval({
  entries, session, turn, tool, input, decisionReason, signal, timeoutMs = DEFAULT_TIMEOUT_MS,
} = {}) {
  const { habits, experiences } = relevantForDecision(entries, {
    workdir: session.workdir,
    tool,
    input,
    prompt: turn?.prompt,
  });

  if (habits.length === 0 && experiences.length === 0) {
    // Nothing to base a decision on — caller should skip the decider entirely.
    return { skipped: 'no-memory', habits: [], experiences: [] };
  }

  const prompt = buildToolPrompt({ session, turn, tool, input, decisionReason, habits, experiences });
  return runDecider({ prompt, session, signal, timeoutMs, habits, experiences,
    expected: ['approve', 'reject'] });
}

// Decide for an AskUserQuestion (returns one of the option labels, or uncertain).
export async function decideAskUserQuestion({
  entries, session, turn, input, signal, timeoutMs = DEFAULT_TIMEOUT_MS,
} = {}) {
  const { habits, experiences } = relevantForDecision(entries, {
    workdir: session.workdir,
    tool: 'AskUserQuestion',
    input,
    prompt: turn?.prompt,
  });
  // For AUQ we'll always invoke if any habit/experience exists OR if any
  // option appears in any past AUQ habit (best-effort relevance check).
  if (habits.length === 0 && experiences.length === 0) {
    return { skipped: 'no-memory', habits: [], experiences: [] };
  }

  const allLabels = collectOptionLabels(input);
  if (allLabels.length === 0) {
    return { skipped: 'no-options', habits: [], experiences: [] };
  }

  const prompt = buildAUQPrompt({ session, turn, input, habits, experiences });
  return runDecider({ prompt, session, signal, timeoutMs, habits, experiences,
    expected: allLabels });
}

async function runDecider({ prompt, session, signal, timeoutMs, habits, experiences, expected }) {
  let result;
  try {
    result = await runClaudeOneShot({
      prompt,
      cwd: session.workdir,
      permissionMode: 'plan',
      signal,
      timeoutMs,
    });
  } catch (e) {
    return { error: e.message, habits, experiences };
  }
  const parsed = extractJson(result.text || '');
  if (!parsed || typeof parsed !== 'object') {
    return { error: 'unparseable JSON', raw: result.text, habits, experiences };
  }
  const decision = String(parsed.decision || '').trim();
  let confidence = Number(parsed.confidence);
  if (!Number.isFinite(confidence)) confidence = 0;
  confidence = Math.max(0, Math.min(1, confidence));
  const reason = redactString(String(parsed.reason || '')).slice(0, 400);
  const usedMemoryIds = Array.isArray(parsed.usedMemoryIds)
    ? parsed.usedMemoryIds.map(String).slice(0, 10) : [];

  // Validate decision against expected set.
  let valid = false;
  if (decision === 'uncertain') valid = true;
  else if (Array.isArray(expected) && expected.includes(decision)) valid = true;

  if (!valid) {
    return {
      decision: 'uncertain', confidence: 0, reason: 'invalid decision: ' + decision,
      usedMemoryIds, habits, experiences,
    };
  }
  return { decision, confidence, reason, usedMemoryIds, habits, experiences,
    usage: result.usage, cost: result.cost };
}

function buildToolPrompt({ session, turn, tool, input, decisionReason, habits, experiences }) {
  const safeInput = redactInput(input);
  return [
    '你是用户的"决策助手"。Claude Code 想执行一个动作，工程策略要求人工确认。',
    '请基于下方"用户记忆"判断该动作是否符合用户习惯，输出严格 JSON：',
    '{"decision":"approve"|"reject"|"uncertain","confidence":0..1,"reason":"...","usedMemoryIds":["..."]}',
    '',
    '【判断原则】',
    '- 记忆与当前情境吻合且方向一致 → approve / reject，confidence 反映吻合程度。',
    '- 记忆少 / 互相矛盾 / 与情境不直接相关 → 必须返回 uncertain，不要猜。',
    '- 不要输出任何解释文字，只输出 JSON。',
    '',
    '【当前情境】',
    `工具：${tool}`,
    `输入：${truncate(JSON.stringify(safeInput), 800)}`,
    `策略要求人工确认的原因：${decisionReason || ''}`,
    `本轮 prompt：${truncate(turn?.prompt || '', 500)}`,
    '',
    '【相关习惯】',
    formatHabits(habits) || '（无）',
    '',
    '【相关经验】',
    formatExperiences(experiences) || '（无）',
    '',
    '现在请输出 JSON：',
  ].join('\n');
}

function buildAUQPrompt({ session, turn, input, habits, experiences }) {
  const labels = collectOptionLabels(input);
  return [
    '你是用户的"决策助手"。Claude Code 弹出了一个选择题，请基于用户记忆替他选择。',
    '输出严格 JSON：{"decision":"<label>"|"uncertain","confidence":0..1,"reason":"...","usedMemoryIds":["..."]}',
    '其中 <label> 必须从下方"选项 label"中精确选择一个。',
    '',
    '【判断原则】',
    '- 记忆里有明确偏好 → 选对应选项；否则返回 uncertain。',
    '- 不要输出 JSON 之外任何文字。',
    '',
    '【当前问题】',
    formatAUQ(input),
    '',
    '【可选 label】',
    labels.map((l) => `- ${l}`).join('\n'),
    '',
    '【相关习惯】',
    formatHabits(habits) || '（无）',
    '',
    '【相关经验】',
    formatExperiences(experiences) || '（无）',
    '',
    `本轮 prompt：${truncate(turn?.prompt || '', 400)}`,
    '',
    '现在请输出 JSON：',
  ].join('\n');
}

function formatHabits(habits) {
  return habits.map((h) => {
    const c = h.counts || {};
    const days = h.lastTs ? Math.round((Date.now() - h.lastTs) / 86400000) : '?';
    return `- id=${h.id} key=${h.keySignature} scope=${h.scope} ${c.approve || 0}✓/${c.reject || 0}✗ 上次 ${days} 天前${h.frozen ? '（已冻结）' : ''}`;
  }).join('\n');
}

function formatExperiences(exps) {
  return exps.map((e) => {
    return `- id=${e.id} title="${redactString(e.title || '')}"\n  ${truncate(redactString(e.body || ''), 400)}`;
  }).join('\n');
}

function formatAUQ(input) {
  const qs = Array.isArray(input?.questions) ? input.questions : [];
  return qs.map((q, i) => {
    const opts = Array.isArray(q.options) ? q.options : [];
    const optLines = opts.map((o) => `  · ${o.label}: ${o.description || ''}`).join('\n');
    return `Q${i + 1}: ${q.question}${q.multiSelect ? '（可多选）' : ''}\n${optLines}`;
  }).join('\n');
}

function collectOptionLabels(input) {
  const qs = Array.isArray(input?.questions) ? input.questions : [];
  const labels = [];
  for (const q of qs) {
    if (Array.isArray(q.options)) {
      for (const o of q.options) {
        if (o.label && typeof o.label === 'string') labels.push(o.label);
      }
    }
  }
  return labels;
}

function truncate(s, n) {
  if (!s) return '';
  const str = String(s);
  return str.length > n ? str.slice(0, n) + '…' : str;
}

